import json
from confluent_kafka import Consumer, Producer, KafkaError, KafkaException

# --- Configuration ---
BOOTSTRAP = "localhost:9092"
INPUT_TOPIC = "raw-payments"
OUTPUT_TOPIC = "enriched-payments"
GROUP_ID = "payment-enricher"

consumer = Consumer({
    "bootstrap.servers": BOOTSTRAP,
    "group.id": GROUP_ID,
    "auto.offset.reset": "earliest",
    "enable.auto.commit": False,
})

producer = Producer({
    "bootstrap.servers": BOOTSTRAP,
    "enable.idempotence": True,
})

def enrich_payment(raw: dict) -> dict:
    """Add computed fields and normalize the event."""
    return {
        **raw,
        "amount_eur": round(raw["amount"] * 0.92, 2),   # Fake FX conversion
        "is_large": raw["amount"] > 1000,
        "enriched": True,
    }

def delivery_report(err, msg):
    if err:
        print(f"Produce failed: {err}")

consumer.subscribe([INPUT_TOPIC])

try:
    while True:
        msg = consumer.poll(1.0)
        if msg is None:
            continue
        if msg.error():
            if msg.error().code() != KafkaError._PARTITION_EOF:
                raise KafkaException(msg.error())
            continue

        raw_event = json.loads(msg.value().decode("utf-8"))

        try:
            enriched = enrich_payment(raw_event)

            # Produce to output topic BEFORE committing input offset
            producer.produce(
                topic=OUTPUT_TOPIC,
                key=msg.key(),
                value=json.dumps(enriched).encode("utf-8"),
                callback=delivery_report,
            )
            producer.poll(0)   # Trigger callbacks

            # Commit input offset only after successfully producing output
            consumer.commit(message=msg)

        except Exception as e:
            print(f"Transform failed for {raw_event}: {e}")
            # Optionally: send to a dead-letter topic instead of dropping

except KeyboardInterrupt:
    pass
finally:
    producer.flush()
    consumer.close()

